using System.ComponentModel;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

/// <summary>
/// Provides web-search and page-fetching tools that the AI agent can invoke.
/// Uses DuckDuckGo's HTML endpoint so no API key is required.
/// </summary>
static partial class WebSearcher
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
            { "Accept", "text/html" },
        },
        Timeout = TimeSpan.FromSeconds(20),
    };

    [Description("Search the web for a query. Returns up to 8 results with titles, URLs, and snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);
            return ParseSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch a web page and return its text content (first ~4 000 characters).")]
    public static async Task<string> FetchPageAsync(
        [Description("The full URL of the page to fetch")] string url)
    {
        Console.WriteLine($"  📄 Fetching: {url}");
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtmlTags(html);
            return text.Length > 4_000
                ? string.Concat(text.AsSpan(0, 4_000), "\n…[truncated]")
                : text;
        }
        catch (Exception ex)
        {
            return $"Fetch failed: {ex.Message}";
        }
    }

    // ── HTML parsing helpers ────────────────────────────────────────────────

    private static string ParseSearchResults(string html)
    {
        var titles = TitleRegex().Matches(html);
        var snippets = SnippetRegex().Matches(html);

        if (titles.Count == 0)
            return "No search results found.";

        var results = new List<string>();

        for (var i = 0; i < Math.Min(titles.Count, 8); i++)
        {
            var title = StripHtmlTags(titles[i].Groups[2].Value).Trim();
            var href = ExtractRealUrl(titles[i].Groups[1].Value);
            var snippet = i < snippets.Count
                ? StripHtmlTags(snippets[i].Groups[1].Value).Trim()
                : "(no snippet)";

            results.Add($"[{i + 1}] {title}\n    URL: {href}\n    {snippet}");
        }

        return string.Join("\n\n", results);
    }

    /// <summary>
    /// DuckDuckGo wraps result URLs in a redirect:
    /// <c>//duckduckgo.com/l/?uddg=ENCODED_URL&amp;rut=…</c>.
    /// This extracts the real destination URL.
    /// </summary>
    private static string ExtractRealUrl(string ddgHref)
    {
        const string marker = "uddg=";
        var idx = ddgHref.IndexOf(marker, StringComparison.Ordinal);
        if (idx < 0) return ddgHref;

        var start = idx + marker.Length;
        var end = ddgHref.IndexOf('&', start);
        var encoded = end > 0 ? ddgHref[start..end] : ddgHref[start..];
        return Uri.UnescapeDataString(encoded);
    }

    private static string StripHtmlTags(string html)
    {
        var text = TagRegex().Replace(html, " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        return CollapseWhitespaceRegex().Replace(text, " ").Trim();
    }

    // ── Source-generated regexes ────────────────────────────────────────────

    [GeneratedRegex("""<a[^>]*class="result__a"[^>]*href="([^"]*)"[^>]*>(.*?)</a>""",
        RegexOptions.Singleline)]
    private static partial Regex TitleRegex();

    [GeneratedRegex("""<a[^>]*class="result__snippet"[^>]*>(.*?)</a>""",
        RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex TagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex CollapseWhitespaceRegex();
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

/// <summary>
/// In-memory notepad that the AI agent uses to record and review research findings
/// before writing its final summary.
/// </summary>
sealed class Notepad
{
    private readonly List<(string Label, string Content)> _notes = [];

    [Description("Save a research finding as a note with a short descriptive label.")]
    public string SaveNote(
        [Description("A short label or category, e.g. 'overview', 'key-dates', 'controversy'")] string label,
        [Description("The note content — the finding or fact to record")] string content)
    {
        _notes.Add((label, content));
        Console.WriteLine($"  📝 Note #{_notes.Count} saved: [{label}]");
        return $"Note #{_notes.Count} saved under '{label}'.";
    }

    [Description("Retrieve all saved research notes to review before writing the summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        Console.WriteLine($"  📓 Reviewing {_notes.Count} note(s)");
        return string.Join("\n\n", _notes.Select((n, i) =>
            $"── Note {i + 1} [{n.Label}] ──\n{n.Content}"));
    }
}

