using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ───────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ── Build the AI client with automatic tool invocation ──────────────────────
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var notepad = new Notepad();

var options = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearcher.SearchAsync),
        AIFunctionFactory.Create(WebSearcher.FetchPageAsync),
        AIFunctionFactory.Create(notepad.SaveNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ],
};

// ── Get the research topic from args or interactive prompt ──────────────────
var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided — exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: \"{topic}\" …\n");

// ── Run the agent ───────────────────────────────────────────────────────────
List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a meticulous research agent. When given a topic:
        1. Perform 3–5 web searches with varied queries to cover different angles.
        2. Optionally fetch full pages when a snippet looks especially promising.
        3. Use SaveNote to record every key finding (give each note a short label).
        4. When done gathering, call GetNotes to review everything you collected.
        5. Write a final, well-structured Markdown summary with:
           - An overview paragraph
           - Key sections with bullet points
           - A "Sources" list at the end
        Be thorough and cover multiple perspectives. Cite your sources.
        """),
    new(ChatRole.User, $"Please research the following topic:\n\n{topic}"),
];

var response = await client.GetChatResponseAsync(messages, options);

Console.WriteLine();
Console.WriteLine("══════════════════════════════════════════════════");
Console.WriteLine("              📋 RESEARCH SUMMARY                ");
Console.WriteLine("══════════════════════════════════════════════════");
Console.WriteLine();
Console.WriteLine(response.Text);

// ── Helpers ─────────────────────────────────────────────────────────────────
static string? PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    return Console.ReadLine()?.Trim();
}

