using System.ComponentModel;
using Microsoft.Extensions.AI;

/// <summary>
/// In-memory notepad that the AI agent uses to record and review research findings
/// before writing its final summary.
/// </summary>
sealed class Notepad
{
    private readonly List<(string Label, string Content)> _notes = [];

    [Description("Save a research finding as a note with a short descriptive label.")]
    public string SaveNote(
        [Description("A short label or category, e.g. 'overview', 'key-dates', 'controversy'")] string label,
        [Description("The note content — the finding or fact to record")] string content)
    {
        _notes.Add((label, content));
        Console.WriteLine($"  📝 Note #{_notes.Count} saved: [{label}]");
        return $"Note #{_notes.Count} saved under '{label}'.";
    }

    [Description("Retrieve all saved research notes to review before writing the summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        Console.WriteLine($"  📓 Reviewing {_notes.Count} note(s)");
        return string.Join("\n\n", _notes.Select((n, i) =>
            $"── Note {i + 1} [{n.Label}] ──\n{n.Content}"));
    }
}

